// Emit one item per search term, read straight from the Configure node so
// this doesn't depend on the seen rows that arrive on the input.

const cfg = $('Configure').first().json;
const terms = Array.isArray(cfg.searchTerms) ? cfg.searchTerms : [];

return terms
  .map((t) => (typeof t === 'string' ? t : (t && t.term) || ''))
  .map((s) => String(s).trim())
  .filter(Boolean)
  .map((term) => ({ json: { term }, pairedItem: { item: 0 } }));

// Parse each Google News SDE response, flatten to article rows, and drop any
// article whose URL we've already seen (from the Data Table seen store) or that
// repeats within this run. Emits one item per NEW article.
//
// Quirks of the Google News SDE response this handles:
//  - the array is `articles`;
//  - each article appears twice, once with a `link` and once without — the
//    link-less copy is skipped by the `!url` guard;
//  - `source` is always empty, so we derive the publisher from the URL host.

const seen = new Set(
  $('Read Seen Articles').all()
    .map((r) => (r.json && r.json.url) || '')
    .filter(Boolean)
);

const parseBody = (item) => {
  const resp = item && item.json && item.json.response;
  if (!resp || resp.body === undefined) return {};
  if (typeof resp.body === 'string') {
    try { return JSON.parse(resp.body); } catch (e) { return {}; }
  }
  return resp.body;
};

const sourceFromUrl = (u) => {
  try { return new URL(u).hostname.replace(/^www\./, ''); } catch (e) { return ''; }
};

const terms = $('Expand Search Terms').all();
const scrapedAt = new Date().toISOString();
const batchSeen = new Set();
const out = [];

$input.all().forEach((item, i) => {
  const term = (terms[i] && terms[i].json && terms[i].json.term) || '';
  const body = parseBody(item);
  const articles = body.articles || body.news_results || body.organic_results || body.results || [];
  if (!Array.isArray(articles)) return;

  for (const a of articles) {
    const url = a.link || a.url || '';
    if (!url || seen.has(url) || batchSeen.has(url)) continue;
    batchSeen.add(url);
    out.push({
      json: {
        search_term: term,
        title: a.title || '',
        url,
        source: (a.source && (a.source.name || a.source)) || a.publisher || a.channel || sourceFromUrl(url),
        published: a.date || a.published_date || a.published || '',
        snippet: a.description || a.snippet || '',
        scraped_at: scrapedAt,
      },
      pairedItem: { item: i },
    });
  }
});

return out;

// Group new articles by matched brand so the digest can be broken out per
// brand, and note which configured brands had zero new mentions. With zero
// new articles this node receives no items and does not run, so nothing is
// posted to Slack.

const articles = $input.all().map((i) => i.json).filter(Boolean);
const today = new Date().toISOString().slice(0, 10);

const cfg = $('Configure').first().json;
const allBrands = (Array.isArray(cfg.searchTerms) ? cfg.searchTerms : [])
  .map((t) => (typeof t === 'string' ? t : (t && t.term) || ''))
  .map((s) => String(s).trim())
  .filter(Boolean);

const groups = {};
for (const a of articles) {
  const brand = a.search_term || 'Other';
  (groups[brand] = groups[brand] || []).push(a);
}

const block = Object.entries(groups).map(([brand, list]) => {
  const items = list.map((a, idx) => [
    `${idx + 1}. ${a.title || '(untitled)'}`,
    a.source ? `   Source: ${a.source}` : '',
    a.published ? `   Published: ${a.published}` : '',
    a.snippet ? `   Snippet: ${a.snippet}` : '',
    a.url ? `   URL: ${a.url}` : '',
  ].filter(Boolean).join('\n')).join('\n');
  return `### ${brand} (${list.length} new)\n${items}`;
}).join('\n\n');

const covered = new Set(Object.keys(groups));
const quietBrands = allBrands.filter((b) => !covered.has(b));

return [{
  json: {
    digest_date: today,
    article_count: articles.length,
    brand_count: covered.size,
    quiet_brands: quietBrands,
    article_block: block,
  },
}];

