// Assemble the final Slack message: a header, the per-brand summary from the
// LLM, and a footer naming any brands with no new mentions.

const d = $('Build Digest Input').first().json;
const summary = ((($input.first() || {}).json || {}).text || '').trim();

const plural = d.brand_count === 1 ? '' : 's';
const header = `*Brand mention digest — ${d.digest_date}*  (${d.article_count} new across ${d.brand_count} brand${plural})`;

const parts = [header, '', summary];

if (Array.isArray(d.quiet_brands) && d.quiet_brands.length) {
  parts.push('', `_No new mentions: ${d.quiet_brands.join(', ')}_`);
}

return [{ json: { slack_text: parts.join('\n') } }];
